-- Region XII (SOCCSKSARGEN): North Cotabato, South Cotabato, Sultan Kudarat, Sarangani, General Santos
-- 'NORTH COTABATO' avoids LIKE-substring collision with SOUTH COTABATO. RDO 108-111 (110 GenSan+Sarangani split).
START TRANSACTION;
DELETE FROM zonal_values WHERE province IN ('NORTH COTABATO','SULTAN KUDARAT','GENERAL SANTOS','SARANGANI','SOUTH COTABATO','COTABATO');
COMMIT;
